var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>기적</color>이 잠들어 있다.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>奇跡</color>が眠っている。","ENG":"Countless <color=#ffd34c>Miracles</color> lie dormant in the Holy Curia's secret library.","TWN":"聖皇廳秘密書庫中沉睡著無數<color=#ffd34c>奇蹟</color>。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"관리국의 존재가 수면 위로 드러나기 전부터 교회가 수집해 온 기적의 실마리들.","JPN":"管理局の存在が明らかになる前から、教会が収集してきた奇跡の手がかり。","ENG":"They are clues that the church had been collecting long before the existence of the Administration was revealed to the public.","TWN":"在管理局的存在浮出水面之前，教會就已經收集了奇蹟的線索。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 소리 내어 읽은 것만으로도 배탈을 치료할 수 있다고 전해지는 마도서부터.","JPN":"たとえるなら、声に出して読んだだけでも腹痛を治癒することができると言われている魔導書から。","ENG":"For instance, there is a grimoire that can cure stomachaches just by reading its passages out loud.","TWN":"比如說，只要大聲朗讀就能治癒腹痛的魔法書。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 누명을 쓰고 새하얀 피를 흘리며 숨을 거둔 순교자의 유언장까지.","JPN":"濡れ衣を着せられて白色の血を流しながら息絶えた殉教者の遺言書まで。","ENG":"Or even the will of a martyr who died after being falsely accused and shedding pure white blood.","TWN":"再比如，背負冤屈，流著純白的血，臨終前的殉教者遺言。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 설립 이래로, 시성성은 수단과 방법을 가리지 않고 기적의 행방을 쫓아왔으며.","JPN":"聖皇庁の設立以来、列聖省は手段を選ばずに奇跡の行方を追跡し。","ENG":"Since the establishment of the Holy Curia, the Dicastery for the Causes of Saints has pursued the whereabouts of Miracles through any means possible.","TWN":"自聖皇廳成立以來，封聖部一直不擇手段地追尋奇蹟的蹤跡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"또한 그 기적에 경중은 없으니…….","JPN":"また、その奇跡に軽重はない……","ENG":"Moreover, no Miracle is weighed greater or lesser than another...","TWN":"而且那奇蹟沒有輕重之分……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"따라서 비밀 서고의 사서는 있는 그대로의 기적, 그 자체를 보존할 의무가 있다.","JPN":"よって、秘密書庫の司書はありのままの奇跡、それ自体を保存する義務がある。","ENG":"Therefore, the librarian of the secret library has a duty to preserve the Miracle itself.","TWN":"因此，秘密書庫的管理員有義務將這些奇蹟原原本本地保存下來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 아무리 사소하고 보잘것없어 보일지라도.","JPN":"時にその奇跡がとても小さく些細なものに見えたとしても。","ENG":"At times, they may seem insignificant.","TWN":"有時候，那些奇蹟看起來微不足道。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 세상에서 완전히 지워버리고 싶을 정도로 낯부끄러운 것일지라도.","JPN":"時にその奇跡がこの世から完全に消しさりたいほど不名誉なことであるとしても。","ENG":"At other times, they are embarrassing to the point one wishes to completely erase the Miracles from the world.","TWN":"有時候，那些奇蹟甚至會讓人羞愧到想要將其徹底從世界上抹去。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"주께서 사서에게 부여하신 의무는 기적의 보존이지, 결코 말소가 아닐 터.","JPN":"主が司書に与えられし義務は奇跡の保存であり、決して抹消ではない。","ENG":"Nevertheless, the duty given to the librarian by the Lord is to preserve, not destroy.","TWN":"但主賦予管理員的職責是保存奇蹟，絕不是抹除。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에…….","JPN":"そのため……","ENG":"And so...","TWN":"正因為如此……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 어린 양이 고해성사의 기도를 올립니다.","JPN":"子羊が告解の祈りを捧げます。","ENG":"I offer a prayer of confession.","TWN":"你的小羊正在懺悔祈禱。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 여기 한 젊은 사서가 고민에 빠졌다.","JPN":"そのためここに、1人の若い司書が悩んでいる。","ENG":"One young librarian finds herself in deep contemplation.","TWN":"因此，這裡有一位年輕的圖書管理員陷入了困境。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 손에 넣은 것은 어느 디저트의 <color=#ffd34c>레시피</color>.","JPN":"彼女が手に入れたのは、あるデザートの<color=#ffd34c>レシピ</color>。","ENG":"She has in her hands a certain dessert <color=#ffd34c>recipe</color>.","TWN":"她得到的是某種甜點的<color=#ffd34c>食譜</color>。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어쩌면 기적을 향한 실마리가 될지도 모르는 것.","JPN":"それはもしかしたら、奇跡への手がかりとなり得るかもしれないもの。","ENG":"Perhaps this, too, could be a clue to a Miracle.","TWN":"那或許是通往奇蹟的線索。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 저를 시험에 들게 하십니까…….","JPN":"私を試さないでください……","ENG":"Why do You lead me into temptation...?","TWN":"為什麼要考驗我……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"평소처럼 냉철한 이성과 신앙심으로 기적의 보존을 행사할 것인지.","JPN":"いつもどおりに冷徹な理性と信仰で奇跡の保存を行うか。","ENG":"Will she continue to preserve the Miracle with her collected reason and faith?","TWN":"是否能像往常一樣，憑藉冷靜的理性和信仰來保存奇蹟。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"사사로운 감정으로 자신이 목도한 기적을 부정하고, 자신의 손으로 말살할 것인지.","JPN":"私情で自分が目撃した奇跡を否定し、自分の手で抹殺するか。","ENG":"Or will she deny the Miracle she has witnessed out of personal feelings and destroy it herself?","TWN":"是否會因私慾而否定自己目睹的奇蹟，並親手將其抹除。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"부디 부덕한 저를 용서하여 주옵소서.","JPN":"どうか、不徳な私をお許しください。","ENG":"Please forgive my being unscrupulous.","TWN":"請你原諒我這個罪人。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"그 날. 새하얀 눈으로 뒤덮인 성야의 날.","JPN":"あの日。純白の雪で覆われた聖夜の日。","ENG":"That holy night, when the world was covered in pure white snow.","TWN":"那一天，被潔白的雪覆蓋的平安夜。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"그 거룩한 밤에 일어난 기적의 행방은 오롯이 이 젊은 사서의 손에 달려 있으니…….","JPN":"あの聖なる夜に起きた奇跡の行方は、まさにこの若い司書の手にかかっている……","ENG":"The Miracle that occurred on that holy night lies solely in the hands of this young librarian...","TWN":"那神聖之夜發生的奇蹟，全都掌握在這位年輕的管理員手中……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"성무 코드 <color=#ffd34c>X12MAS25</color>.","JPN":"聖務コード<color=#ffd34c>X12MAS25</color>。","ENG":"Sacred Mission Code <color=#ffd34c>X12MAS25</color>.","TWN":"聖務代碼<color=#ffd34c>X12MAS25</color>。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"통칭, <color=#ffd34c>성야의 쇼콜라 무스 케이크 사건</color>.","JPN":"通称、<color=#ffd34c>聖夜のムースショコラ事件</color>。","ENG":"A.K.A, <color=#ffd34c>The Holy Night Chocolate Mousse Cake Incident</color>.","TWN":"統稱，<color=#ffd34c>平安夜巧克力慕斯事件</color>。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것은, 그 달콤하고도 끔찍한 디저트로부터 시작되었다.","JPN":"すべては、その甘く残酷なデザートから始まった。","ENG":"It all started from that sweet yet horrendous dessert.","TWN":"一切都始於那道甜美又可怕的甜點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>사건</color> 보름 전","JPN":"<color=#ffd34c>事件</color>の2週間前","ENG":"2 weeks before <color=#ffd34c>the incident</color>","TWN":"<color=#ffd34c>事件</color> 發生半個月前"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};